nta.declaration:
const int MAX_CLIENTS = 1;
typedef int[0, MAX_CLIENTS-1] client_id_t;

// 客户端状态（与 Level1 一致）
const int CLIENT_STATE_INIT = 0;
const int CLIENT_STATE_BOOTSTRAPPING = 1;
const int CLIENT_STATE_BOOTSTRAP_COMPLETE = 2;
const int CLIENT_STATE_ERROR = 12;

// 广播通道（与 Level1 一致）
broadcast chan bootstrap_start_client[MAX_CLIENTS];
broadcast chan bootstrap_credential[MAX_CLIENTS];
broadcast chan bootstrap_config[MAX_CLIENTS];
broadcast chan bootstrap_complete[MAX_CLIENTS];

// 新增 ACK 通道
broadcast chan ack_start[MAX_CLIENTS];   // 服务器 -> 客户端 ACK（对应 bootstrap_start）
broadcast chan ack_config[MAX_CLIENTS];   // 客户端 -> 服务器 ACK（对应 bootstrap_config）

// 概率参数
const double LOSS_PROB = 0.005;
const int WEIGHT_SUCCESS = 995;
const int WEIGHT_LOSS = 5;

// DTLS 延迟（可配置）
const int DTLS_HANDSHAKE_DELAY = 80;
const int DTLS_ENCRYPT_DELAY = 6;
const int DTLS_DECRYPT_DELAY = 5;

// 重传参数
const int MAX_RETRANSMIT = 4;
const int ACK_TIMEOUT = 50;               // 单次等待 ACK 超时
const int SERVER_TIMEOUT = 500;           // 服务器等待请求超时

// 统计变量
int client_bootstrapped = 0;
int notification_failed = 0;
int notification_sent = 0;
int retransmission_count = 0;

// 开关
bool security_enabled = true;
bool retransmission_enabled = false;

template.declaration:
clock clk;
int retry_start = 0;       // bootstrap_start 重传次数
int retry_config = 0;      // bootstrap_config 重传次数

clock t;
int current_client = 0;
int retry_config = 0;      // server retransmission count

nta.system:
Client1 = Client(0);
BootstrapHandler1 = BootstrapHandler();

system Client1,  BootstrapHandler1;
